    inner_tile = 0
    for dim_idx in range(len(iteration_type) - 1, -1, -1):
        if iteration_type[dim_idx] == PARALLEL:
            # Use the last (innermost) tile level for this dimension
            for level in reversed(tile_sizes):
                val = level[dim_idx] if dim_idx < len(level) else 0
                if val > 0:
                    inner_tile = val
                    break
            if inner_tile > 0:
                break

    if inner_tile == 0:
        return 0.0

    # Utilization = how well the tile fills vector registers
    # If tile >= vlmax, full utilization of at least one register
    if inner_tile >= vlmax:
        return 1.0

    return inner_tile / vlmax


